import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        if (input.length() > 10) {
            System.out.println("Input length exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Use input length to create buffer of appropriate size
        byte[] buffer = new byte[input.length()];

        // Copy input bytes to buffer
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
